(8, 1, '2026-02-26 11:20:57', '2026-02-26 10:20:57', '<img width=\"108\" height=\"94\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/Fichier-2.png\" alt=\"\" />																<h2>INTERIOR DESIGN</h2>		<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Ut elit tellus, luctus nec ullamcorper mattis, pulvinar dapibus leo.</p>													<img width=\"95\" height=\"94\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/FASHION-ICONE.png\" alt=\"\" />																<h2>FASHION</h2>		<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Ut elit tellus, luctus nec ullamcorper mattis, pulvinar dapibus leo.</p>													<img width=\"94\" height=\"94\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/ICON-GRAPHIC-DESIGN.png\" alt=\"\" />																<h2>DESIGN</h2>		<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Ut elit tellus, luctus nec ullamcorper mattis, pulvinar dapibus leo.</p>								<a href=\"#\">\n									More Informations\n					</a>\n														<a href=\"#\">\n									More Informations\n					</a>\n														<a href=\"#\">\n									More Informations\n					</a>\n									<h2>feedback from Our Clients</h2>							\n							“Professional, fast, and incredibly talented.Our brand identity has never looked so strong.We highly recommend their services.”<br>Jonathan Reed, Founder of Reed Digital\n							<img width=\"4160\" height=\"6240\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/client2.jpg\" alt=\"\" />						\n							“Professional, fast, and incredibly talented.Our brand identity has never looked so strong.We highly recommend their services.”<br>Jonathan Reed, Founder of Reed Digital\n							<img width=\"5461\" height=\"8192\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/client3.jpg\" alt=\"\" />						\n							“Professional, fast, and incredibly talented.Our brand identity has never looked so strong.We highly recommend their services.”<br>Jonathan Reed, Founder of Reed Digital\n							<img width=\"3830\" height=\"5745\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/client-1.jpg\" alt=\"\" />						\n							<h2>If you can dream it,<br>we can make it.</h2>		<p>I\'m a fashion student passionate about exploring&nbsp;</p><p>contemporary styles and innovative textile concepts.</p>\n<p>I\'m dedicated to developing a unique design&nbsp;</p><p>identity that blends creativity, culture, and modern aesthetics.</p>			<h2>Find our lacation !</h2>							\n			<iframe loading=\"lazy\"\n					src=\"https://maps.google.com/maps?q=universit%C3%A9%20Gaston%20Berger&#038;t=m&#038;z=12&#038;output=embed&#038;iwloc=near\"\n					title=\"université Gaston Berger\"\n					aria-label=\"université Gaston Berger\"\n			></iframe>\n																	<img width=\"204\" height=\"67\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/white-logo.png\" alt=\"\" />																										<img width=\"114\" height=\"115\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/qr-code-50.jpg\" alt=\"\" />																											<a href=\"#\">\n							<img width=\"44\" height=\"44\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/Fichier-5.png\" alt=\"\" />								</a>\n																											<a href=\"#\">\n							<img width=\"42\" height=\"42\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/Fichier-9.png\" alt=\"\" />								</a>\n																											<a href=\"#\">\n							<img width=\"42\" height=\"42\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/Fichier-8.png\" alt=\"\" />								</a>\n																											<a href=\"#\">\n							<img width=\"41\" height=\"41\" src=\"http://localhost/dcollective/wp-content/uploads/2026/03/Fichier-10.png\" alt=\"\" />								</a>', 'accueil', '', 'publish', 'closed', 'closed', '', 'accueil', '', '', '2026-05-11 17:59:23', '2026-05-11 15:59:23', '', 0, 'http://localhost/dcollective/?page_id=8', 0, 'page', '', 0),
